from flask import Flask, request, jsonify
import numpy as np
import cv2
import os
from sklearn import svm
from sklearn.preprocessing import LabelEncoder
from sklearn.metrics import accuracy_score
import pickle

app = Flask(__name__)

# Load employee photos from a directory
def load_employee_photos(directory):
    images = []
    labels = []
    for label in os.listdir(directory):
        for image_name in os.listdir(os.path.join(directory, label)):
            img_path = os.path.join(directory, label, image_name)
            image = cv2.imread(img_path)
            if image is not None:
                image = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
                image = cv2.resize(image, (100, 100)).flatten()
                images.append(image)
                labels.append(label)
    return np.array(images), np.array(labels)

# Train the SVM model for facial recognition
def train_model():
    images, labels = load_employee_photos('employee_photos')
    le = LabelEncoder()
    labels_encoded = le.fit_transform(labels)
    
    clf = svm.SVC(probability=True)
    clf.fit(images, labels_encoded)

    with open('model.pkl', 'wb') as model_file:
        pickle.dump((clf, le), model_file)

# Load the trained model
def load_model():
    with open('model.pkl', 'rb') as model_file:
        return pickle.load(model_file)

@app.route('/train', methods=['POST'])
def train():
    train_model()
    return jsonify({'status': 'model trained successfully'}), 200

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    file = request.files['image']
    file.save('temp_image.jpg')

    image = cv2.imread('temp_image.jpg')
    image = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    image = cv2.resize(image, (100, 100)).flatten()

    clf, le = load_model()
    probability_distribution = clf.predict_proba([image])
    confidence_scores = {le.inverse_transform([i])[0]: prob for i, prob in enumerate(probability_distribution[0])}

    return jsonify(confidence_scores), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)